#include <stdio.h>
#include <stdlib.h>
int main(){
    const int PASSING_MARK=40;
    char line[256];
    if(!fgets(line,sizeof(line),stdin))return 0;
    int T=atoi(line);
    for(int i=0;i<T;++i){
        if(!fgets(line,sizeof(line),stdin))break;
        int score=atoi(line);
        if(score>=PASSING_MARK)puts("You passed the exam!");
    }
    return 0;
}

