import sys
def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    PASSING_MARK=40
    out=[]
    for _ in range(T):
        try:
            score=int(next(it))
        except StopIteration:
            break
        if score>=PASSING_MARK:
            out.append("You passed the exam!")
    sys.stdout.write("\n".join(out))
if __name__=="__main__":
    main()

